import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

const PsychometricTest = () => {
  const [currentQuestion, setCurrentQuestion] = useState(0);
  const [answers, setAnswers] = useState([]);
  const [showResults, setShowResults] = useState(false);
  const [results, setResults] = useState(null);
  const { user, token } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  
  // Get quiz results from previous page
  const quizResults = location.state?.quizResults;

  // Psychometric test questions based on Big Five personality traits + career interests
  const questions = [
    // Openness to Experience
    {
      id: 1,
      question: "I enjoy exploring new ideas and concepts, even if they seem unconventional.",
      trait: "openness",
      scale: "agree"
    },
    {
      id: 2,
      question: "I prefer practical, proven methods over experimental approaches.",
      trait: "openness",
      scale: "disagree"
    },
    // Conscientiousness
    {
      id: 3,
      question: "I always complete my assignments on time and follow through on commitments.",
      trait: "conscientiousness",
      scale: "agree"
    },
    {
      id: 4,
      question: "I often procrastinate and struggle with time management.",
      trait: "conscientiousness",
      scale: "disagree"
    },
    // Extraversion
    {
      id: 5,
      question: "I feel energized when working in groups and collaborating with others.",
      trait: "extraversion",
      scale: "agree"
    },
    {
      id: 6,
      question: "I prefer working alone and find large groups draining.",
      trait: "extraversion",
      scale: "disagree"
    },
    // Analytical Thinking
    {
      id: 7,
      question: "I enjoy solving complex mathematical or logical problems.",
      trait: "analytical",
      scale: "agree"
    },
    {
      id: 8,
      question: "I prefer creative tasks over analytical problem-solving.",
      trait: "analytical",
      scale: "disagree"
    },
    // Leadership
    {
      id: 9,
      question: "I naturally take charge in group situations and enjoy leading others.",
      trait: "leadership",
      scale: "agree"
    },
    {
      id: 10,
      question: "I prefer to follow others' lead rather than take responsibility for decisions.",
      trait: "leadership",
      scale: "disagree"
    },
    // Creativity
    {
      id: 11,
      question: "I often come up with original ideas and enjoy artistic expression.",
      trait: "creativity",
      scale: "agree"
    },
    {
      id: 12,
      question: "I prefer structured tasks with clear guidelines over open-ended creative work.",
      trait: "creativity",
      scale: "disagree"
    },
    // Social Interest
    {
      id: 13,
      question: "I am passionate about helping others and making a positive social impact.",
      trait: "social",
      scale: "agree"
    },
    {
      id: 14,
      question: "I am more interested in technical achievements than helping people.",
      trait: "social",
      scale: "disagree"
    },
    // Risk Tolerance
    {
      id: 15,
      question: "I am comfortable taking calculated risks for potential rewards.",
      trait: "risk_tolerance",
      scale: "agree"
    },
    {
      id: 16,
      question: "I prefer safe, predictable choices over uncertain opportunities.",
      trait: "risk_tolerance",
      scale: "disagree"
    },
    // Detail Orientation
    {
      id: 17,
      question: "I pay close attention to details and rarely make careless mistakes.",
      trait: "detail_oriented",
      scale: "agree"
    },
    {
      id: 18,
      question: "I focus on the big picture and sometimes overlook small details.",
      trait: "detail_oriented",
      scale: "disagree"
    },
    // Communication
    {
      id: 19,
      question: "I excel at explaining complex ideas clearly to others.",
      trait: "communication",
      scale: "agree"
    },
    {
      id: 20,
      question: "I find it challenging to express my thoughts verbally or in writing.",
      trait: "communication",
      scale: "disagree"
    }
  ];

  const options = [
    { value: 1, text: "Strongly Disagree" },
    { value: 2, text: "Disagree" },
    { value: 3, text: "Neutral" },
    { value: 4, text: "Agree" },
    { value: 5, text: "Strongly Agree" }
  ];

  const handleAnswerSelect = (value) => {
    const newAnswers = [...answers];
    newAnswers[currentQuestion] = {
      questionId: questions[currentQuestion].id,
      trait: questions[currentQuestion].trait,
      scale: questions[currentQuestion].scale,
      value: value
    };
    setAnswers(newAnswers);

    setTimeout(() => {
      if (currentQuestion < questions.length - 1) {
        setCurrentQuestion(currentQuestion + 1);
      } else {
        calculateResults(newAnswers);
      }
    }, 300);
  };

  const calculateResults = (finalAnswers) => {
    // Calculate trait scores
    const traitScores = {
      openness: 0,
      conscientiousness: 0,
      extraversion: 0,
      analytical: 0,
      leadership: 0,
      creativity: 0,
      social: 0,
      risk_tolerance: 0,
      detail_oriented: 0,
      communication: 0
    };

    finalAnswers.forEach(answer => {
      let score = answer.value;
      // Reverse score for "disagree" scale questions
      if (answer.scale === "disagree") {
        score = 6 - score;
      }
      traitScores[answer.trait] += score;
    });

    // Normalize scores (each trait has 2 questions, so max score is 10)
    Object.keys(traitScores).forEach(trait => {
      traitScores[trait] = Math.round((traitScores[trait] / 10) * 100);
    });

    // Combine with quiz results for final career recommendations
    const combinedResults = combineResults(quizResults, traitScores);
    
    setResults(combinedResults);
    setShowResults(true);
  };

  const combineResults = (quiz, personality) => {
    // Career mapping based on quiz streams and personality traits
    const careerRecommendations = [];

    // Science stream careers
    if (quiz?.streamPercentages?.science > 30) {
      if (personality.analytical > 70 && personality.detail_oriented > 60) {
        careerRecommendations.push({
          career: "Research Scientist",
          match: 95,
          reason: "High analytical skills and attention to detail, strong science aptitude"
        });
      }
      if (personality.creativity > 60 && personality.openness > 70) {
        careerRecommendations.push({
          career: "Innovation Engineer",
          match: 88,
          reason: "Creative problem-solving with scientific knowledge"
        });
      }
      if (personality.social > 70 && personality.communication > 60) {
        careerRecommendations.push({
          career: "Science Teacher/Professor",
          match: 85,
          reason: "Strong science background with excellent communication skills"
        });
      }
    }

    // Commerce stream careers
    if (quiz?.streamPercentages?.commerce > 30) {
      if (personality.leadership > 70 && personality.risk_tolerance > 60) {
        careerRecommendations.push({
          career: "Entrepreneur/Business Owner",
          match: 92,
          reason: "Strong leadership and risk tolerance with business acumen"
        });
      }
      if (personality.analytical > 70 && personality.detail_oriented > 70) {
        careerRecommendations.push({
          career: "Financial Analyst",
          match: 90,
          reason: "Excellent analytical skills and attention to detail in finance"
        });
      }
      if (personality.extraversion > 70 && personality.communication > 70) {
        careerRecommendations.push({
          career: "Sales Manager",
          match: 87,
          reason: "Strong interpersonal skills with business knowledge"
        });
      }
    }

    // Arts stream careers
    if (quiz?.streamPercentages?.arts > 30) {
      if (personality.creativity > 80 && personality.openness > 70) {
        careerRecommendations.push({
          career: "Creative Director",
          match: 94,
          reason: "Exceptional creativity and openness to new ideas"
        });
      }
      if (personality.social > 70 && personality.communication > 70) {
        careerRecommendations.push({
          career: "Social Worker/Counselor",
          match: 89,
          reason: "Strong empathy and communication skills"
        });
      }
      if (personality.communication > 80 && personality.creativity > 60) {
        careerRecommendations.push({
          career: "Content Writer/Journalist",
          match: 86,
          reason: "Excellent writing skills with creative thinking"
        });
      }
    }

    // Diploma/Technical careers
    if (quiz?.streamPercentages?.diploma > 30) {
      if (personality.detail_oriented > 70 && personality.conscientiousness > 70) {
        careerRecommendations.push({
          career: "Technical Specialist",
          match: 91,
          reason: "High attention to detail and reliability in technical work"
        });
      }
      if (personality.analytical > 60 && personality.creativity > 60) {
        careerRecommendations.push({
          career: "Product Designer",
          match: 88,
          reason: "Balance of technical skills and creative problem-solving"
        });
      }
    }

    // Sort by match percentage and take top 5
    careerRecommendations.sort((a, b) => b.match - a.match);
    
    return {
      quizResults: quiz,
      personalityTraits: personality,
      careerRecommendations: careerRecommendations.slice(0, 5),
      topTraits: Object.entries(personality)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 3)
        .map(([trait, score]) => ({ trait, score }))
    };
  };

  const goToPrevious = () => {
    if (currentQuestion > 0) {
      setCurrentQuestion(currentQuestion - 1);
    }
  };

  if (!quizResults) {
    return (
      <div className="max-w-4xl mx-auto px-4 py-8">
        <div className="card text-center">
          <h2 className="text-xl font-semibold mb-4">Access Denied</h2>
          <p className="text-gray-600 mb-4">Please complete the career quiz first.</p>
          <button onClick={() => navigate('/quiz')} className="btn-primary">
            Take Career Quiz
          </button>
        </div>
      </div>
    );
  }

  if (showResults) {
    return (
      <div className="max-w-6xl mx-auto px-4 py-8">
        <div className="card">
          <h1 className="text-3xl font-bold text-center mb-8">Your Complete Career Analysis</h1>
          
          {/* Career Recommendations */}
          <div className="mb-8">
            <h2 className="text-2xl font-semibold mb-6">Top Career Recommendations</h2>
            <div className="grid gap-4">
              {results.careerRecommendations.map((career, index) => (
                <div key={index} className="p-6 bg-gradient-to-r from-primary-50 to-blue-50 rounded-lg border-l-4 border-primary-600">
                  <div className="flex items-center justify-between mb-2">
                    <h3 className="text-xl font-semibold text-primary-800">{career.career}</h3>
                    <span className="text-2xl font-bold text-primary-600">{career.match}%</span>
                  </div>
                  <p className="text-gray-700">{career.reason}</p>
                </div>
              ))}
            </div>
          </div>

          {/* Personality Traits */}
          <div className="grid md:grid-cols-2 gap-8 mb-8">
            <div>
              <h2 className="text-xl font-semibold mb-4">Your Top Personality Traits</h2>
              <div className="space-y-3">
                {results.topTraits.map(({ trait, score }) => (
                  <div key={trait} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <span className="capitalize font-medium">{trait.replace('_', ' ')}</span>
                    <div className="flex items-center">
                      <div className="w-32 bg-gray-200 rounded-full h-2 mr-3">
                        <div
                          className="bg-green-600 h-2 rounded-full"
                          style={{ width: `${score}%` }}
                        ></div>
                      </div>
                      <span className="text-sm font-medium">{score}%</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div>
              <h2 className="text-xl font-semibold mb-4">Academic Stream Analysis</h2>
              <div className="space-y-3">
                {Object.entries(results.quizResults.streamPercentages || {}).map(([stream, percentage]) => (
                  <div key={stream} className="flex items-center justify-between p-3 bg-gray-50 rounded-lg">
                    <span className="capitalize font-medium">{stream}</span>
                    <div className="flex items-center">
                      <div className="w-32 bg-gray-200 rounded-full h-2 mr-3">
                        <div
                          className="bg-primary-600 h-2 rounded-full"
                          style={{ width: `${percentage}%` }}
                        ></div>
                      </div>
                      <span className="text-sm font-medium">{percentage}%</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>

          <div className="text-center">
            <div className="flex justify-center space-x-4 flex-wrap gap-2">
              <button onClick={() => navigate('/quiz')} className="btn-secondary">
                Retake Assessment
              </button>
              <button onClick={() => navigate('/courses')} className="btn-primary">
                Explore Courses
              </button>
              <button onClick={() => navigate('/colleges')} className="btn-primary">
                Find Colleges
              </button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  const currentQ = questions[currentQuestion];

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <div className="card">
        <div className="mb-6">
          <div className="flex items-center justify-between mb-4">
            <h1 className="text-2xl font-bold">Psychometric Assessment</h1>
            <div className="text-right">
              <span className="text-sm text-gray-600">
                Question {currentQuestion + 1} of {questions.length}
              </span>
              <div className="text-xs text-gray-500">
                Personality & Career Traits
              </div>
            </div>
          </div>

          <div className="w-full bg-gray-200 rounded-full h-2">
            <div
              className="bg-primary-600 h-2 rounded-full transition-all duration-300"
              style={{ width: `${((currentQuestion + 1) / questions.length) * 100}%` }}
            ></div>
          </div>
        </div>

        <div className="mb-8">
          <h2 className="text-xl font-semibold mb-6">
            {currentQ.question}
          </h2>

          <div className="space-y-3">
            {options.map((option, index) => (
              <button
                key={option.value}
                onClick={() => handleAnswerSelect(option.value)}
                className="w-full p-4 text-left border-2 border-gray-200 rounded-lg hover:border-green-500 hover:bg-green-50 transition-all duration-300 cursor-pointer"
              >
                <div className="flex items-center">
                  <span className="w-8 h-8 rounded-full flex items-center justify-center text-sm font-medium mr-3 bg-gray-100 text-gray-700">
                    {option.value}
                  </span>
                  <span>{option.text}</span>
                </div>
              </button>
            ))}
          </div>
        </div>

        <div className="flex justify-between">
          <button
            onClick={goToPrevious}
            disabled={currentQuestion === 0}
            className={`btn-secondary ${currentQuestion === 0 ? 'opacity-50 cursor-not-allowed' : ''}`}
          >
            Previous Question
          </button>

          <div className="text-sm text-gray-500">
            Personality Assessment • Career Matching
          </div>
        </div>
      </div>
    </div>
  );
};

export default PsychometricTest;
